{
  "type": "object",
  "properties": {
    "intencion": {
      "type": "string",
      "enum": [
        "SALUDO", "INFO_EMPRESA", "INFO_PRODUCTO", "PRECIOS_COTIZACION", 
        "PERSONALIZACION", "MUESTRAS", "LOGISTICA_ENTREGA", "REGULATORIO", 
        "CONTACTO_HUMANO", "ENTREGA_DATOS", "OTRO"
      ],
      "description": "Clasificación de la intención principal del usuario."
    },
    "nivel_interes": {
      "type": "string",
      "enum": ["BAJO", "MEDIO", "ALTO"],
      "description": "Nivel de interés comercial detectado."
    },
    "tipo_cliente": {
      "type": "string",
      "enum": ["AGENCIA", "CLIENTE_FINAL", "INDETERMINADO"],
      "description": "Clasifica al usuario según si compra para sí mismo o revende/gestiona para terceros."
    },
    "datos_detectados": {
      "type": "array",
      "items": {
        "type": "string",
        "enum": ["NOMBRE", "EMAIL", "TELEFONO", "EMPRESA"]
      },
      "description": "Lista de datos válidos encontrados explícitamente en el mensaje."
    },
    "datos_faltantes": {
      "type": "array",
      "items": {
        "type": "string",
        "enum": ["NOMBRE", "EMAIL", "EMPRESA"]
      },
      "description": "Lista de datos OBLIGATORIOS que aún NO ha dado el usuario."
    }
  },
  "required": ["intencion", "nivel_interes", "tipo_cliente", "datos_detectados", "datos_faltantes"]
}

