// Obtener email del payload anterior
const targetEmail = $('format:_prep_crm_payload').first().json.email;

if (!targetEmail) {
  return []; 
}

// Normalizar para evitar errores de tipeo
const normalizedTarget = targetEmail.trim().toLowerCase();

// Buscar coincidencia exacta
const foundLead = items.find(item => {
  const leadEmail = item.json.email || '';
  return leadEmail.trim().toLowerCase() === normalizedTarget;
});

if (foundLead) {
  // Lead encontrado: marcar flag
  foundLead.json.leadExists = true;
  return [foundLead];
} else {
  return [];
}

